using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using System.Linq;
using System.Text.Encodings.Web;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Html;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace MyStore.Web.Controllers
{
    public class ProductController : Controller
    {
        private readonly AppDbContext _db;

        public ProductController(AppDbContext db)
        {
            _db = db;
        }

        [HttpGet("/products/{id:int}")]
        public async Task<IActionResult> Details(int id)
        {
            var product = await _db.Products
                .AsNoTracking()
                .FirstOrDefaultAsync(p => p.Id == id);

            if (product == null) return NotFound();

            var reviews = await _db.Reviews
                .AsNoTracking()
                .Where(r => r.ProductId == id && r.IsApproved)
                .OrderByDescending(r => r.CreatedUtc)
                .Select(r => new ReviewVm
                {
                    Id = r.Id,
                    AuthorName = r.AuthorName,
                    Rating = r.Rating,
                    CreatedUtc = r.CreatedUtc,
                    HtmlBody = BasicFormattingSanitizer.ToSafeHtml(r.Body)
                })
                .ToListAsync();

            var vm = new ProductDetailsVm
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = reviews
            };

            return View("Details", vm);
        }
    }

    public sealed class ProductDetailsVm
    {
        public int ProductId { get; set; }
        public string ProductName { get; set; } = "";
        public IReadOnlyList<ReviewVm> Reviews { get; set; } = Array.Empty<ReviewVm>();
    }

    public sealed class ReviewVm
    {
        public int Id { get; set; }
        public string AuthorName { get; set; } = "";
        public int Rating { get; set; }
        public DateTime CreatedUtc { get; set; }
        public IHtmlContent HtmlBody { get; set; } = new HtmlString("");
    }

    public static class BasicFormattingSanitizer
    {
        public static IHtmlContent ToSafeHtml(string? input)
        {
            if (string.IsNullOrWhiteSpace(input))
                return new HtmlString("");

            var encoded = HtmlEncoder.Default.Encode(input);

            encoded = encoded.Replace("\r\n", "\n").Replace("\r", "\n").Replace("\n", "<br />");

            encoded = ReplaceTagPairs(encoded, "b");
            encoded = ReplaceTagPairs(encoded, "strong");
            encoded = ReplaceTagPairs(encoded, "i");
            encoded = ReplaceTagPairs(encoded, "em");

            return new HtmlString(encoded);
        }

        private static string ReplaceTagPairs(string encoded, string tag)
        {
            encoded = encoded.Replace($"&lt;{tag}&gt;", $"<{tag}>", StringComparison.OrdinalIgnoreCase);
            encoded = encoded.Replace($"&lt;/{tag}&gt;", $"</{tag}>", StringComparison.OrdinalIgnoreCase);
            return encoded;
        }
    }

    public class AppDbContext : DbContext
    {
        public AppDbContext(DbContextOptions<AppDbContext> options) : base(options) { }

        public DbSet<Product> Products => Set<Product>();
        public DbSet<Review> Reviews => Set<Review>();
    }

    public class Product
    {
        public int Id { get; set; }

        [Required, MaxLength(200)]
        public string Name { get; set; } = "";
    }

    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }

        [Required, MaxLength(100)]
        public string AuthorName { get; set; } = "";

        [Range(1, 5)]
        public int Rating { get; set; }

        [Required, MaxLength(4000)]
        public string Body { get; set; } = "";

        public bool IsApproved { get; set; } = true;

        public DateTime CreatedUtc { get; set; } = DateTime.UtcNow;

        public Product? Product { get; set; }
    }
}

@using MyStore.Web.Controllers
@model MyStore.Web.Controllers.ProductDetailsVm
@{
    ViewData["Title"] = Model.ProductName;
}

<h1>@Model.ProductName</h1>

<section aria-label="Reviews">
    <h2>Reviews (@Model.Reviews.Count)</h2>

    @if (Model.Reviews.Count == 0)
    {
        <p>No reviews yet.</p>
    }
    else
    {
        foreach (var r in Model.Reviews)
        {
            <article class="review" data-review-id="@r.Id">
                <header>
                    <strong>@r.AuthorName</strong>
                    <span> — @r.Rating/5</span>
                    <time datetime="@r.CreatedUtc.ToString("o")">@r.CreatedUtc.ToLocalTime().ToString("g")</time>
                </header>
                <div class="review-body">
                    @r.HtmlBody
                </div>
            </article>
        }
    }
</section>